export default function MarketSection() {
  const { t, lang } = useTranslation();
  const sectionRef = useRef<HTMLDivElement>(null);
  const isInView = useInView(sectionRef, { once: true, margin: '-80px' });

  const mapRef = useRef<HTMLDivElement>(null);
  const isMapInView = useInView(mapRef, { once: true, margin: '-60px' });

  return (
    <section
      id="market"
      ref={sectionRef}
      className="relative py-[var(--section-v)] overflow-hidden"
      style={{ background: 'var(--cream)' }}
    >
      {/* Texture overlay */}
      <div className="texture-nakshi-diamond absolute inset-0 pointer-events-none" />

      <div className="relative z-10 w-full max-w-[var(--site-max)] mx-auto px-6">
        {/* ─── Eyebrow ─── */}
        <motion.div
          className="text-center mb-6"
          initial={{ opacity: 0, y: 20 }}
          animate={isInView ? { opacity: 1, y: 0 } : {}}
          transition={{ duration: 0.6 }}
        >
          <span
            className="font-body uppercase tracking-widest inline-block"
            style={{ fontSize: 'var(--fs-label)', color: 'var(--text-muted)' }}
          >
            {t('market.eyebrow')}
          </span>
        </motion.div>

        {/* ─── Big Number Headline ─── */}
        <motion.h2
          className="font-bengali text-center mb-4"
          style={{
            fontSize: 'clamp(48px, 7vw, 96px)',
            color: 'var(--text-ink)',
            lineHeight: 1.1,
          }}
          initial={{ opacity: 0, y: 30 }}
          animate={isInView ? { opacity: 1, y: 0 } : {}}
          transition={{ duration: 0.8, delay: 0.1 }}
        >
          {t('market.headline')}
        </motion.h2>

        <motion.p
          className="font-bengali text-center text-lg md:text-xl mb-2"
          style={{ color: 'var(--text-body)' }}
          initial={{ opacity: 0, y: 20 }}
          animate={isInView ? { opacity: 1, y: 0 } : {}}
          transition={{ duration: 0.6, delay: 0.2 }}
        >
          {t('market.sub')}
        </motion.p>

        <motion.p
          className="font-body text-center max-w-2xl mx-auto mb-20"
          style={{ fontSize: 'var(--fs-body)', color: 'var(--text-muted)' }}
          initial={{ opacity: 0, y: 20 }}
          animate={isInView ? { opacity: 1, y: 0 } : {}}
          transition={{ duration: 0.6, delay: 0.3 }}
        >
          {t('market.subEn')}
        </motion.p>

        {/* ─── Three-Column Stat Grid ─── */}
        <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-24">
          <StatCard
            number={98}
            numberSuffix="%"
            bengali={t('market.stats.noDigital.bn')}
            english={t('market.stats.noDigital.en')}
            color="var(--crimson)"
            isInView={isInView}
            delay={0.4}
          />
          <StatCard
            number={85}
            numberSuffix="%"
            bengali={t('market.stats.smartphone.bn')}
            english={t('market.stats.smartphone.en')}
            color="var(--gold)"
            isInView={isInView}
            delay={0.5}
          />
          <StatCard
            number={3.7}
            numberSuffix="×"
            bengali={t('market.stats.profitable.bn')}
            english={t('market.stats.profitable.en')}
            color="var(--gold)"
            isInView={isInView}
            delay={0.6}
          />
        </div>

        {/* ─── Bangladesh District Map ─── */}
        <div ref={mapRef} className="mb-24">
          <div
            className="rounded-2xl p-8 md:p-12 mx-auto max-w-3xl"
            style={{ background: 'var(--ink)' }}
          >
            <motion.svg
              viewBox="0 0 110 90"
              className="w-full h-auto"
              fill="none"
              initial={{ opacity: 0 }}
              animate={isMapInView ? { opacity: 1 } : {}}
              transition={{ duration: 0.8 }}
            >
              {/* Country outline */}
              <path
                d={BANGLADESH_PATH}
                fill="rgba(201, 169, 110, 0.05)"
                stroke="var(--gold)"
                strokeWidth={0.5}
                strokeOpacity={0.3}
              />
              {/* Division dots */}
              {DIVISION_DOTS.map((dot, i) => (
                <MapDot
                  key={dot.name}
                  x={dot.x}
                  y={dot.y}
                  delay={i * 0.08}
                  isInView={isMapInView}
                />
              ))}
            </motion.svg>

            <p
              className="font-body text-center mt-4 text-xs"
              style={{ color: 'var(--text-cream-muted)' }}
            >
              {t('market.mapCaption')}
            </p>
          </div>
        </div>

        {/* ─── Pull Quote ─── */}
        <motion.blockquote
          className="mx-auto text-center mb-20"
          style={{ maxWidth: '700px' }}
          initial={{ opacity: 0, y: 30 }}
          animate={isInView ? { opacity: 1, y: 0 } : {}}
          transition={{ duration: 0.8, delay: 0.7 }}
        >
          <div
            className="font-display italic leading-relaxed"
            style={{
              fontSize: 'clamp(20px, 2.5vw, 28px)',
              color: 'var(--text-body)',
              borderLeft: '3px solid var(--gold)',
              paddingLeft: '20px',
              textAlign: 'left',
            }}
          >
            {t('market.pullQuote')}
          </div>
        </motion.blockquote>

        {/* ─── Bottom Stats Bar ─── */}
        <motion.div
          className="text-center font-bengali"
          style={{ fontSize: '18px', color: 'var(--gold)' }}
          initial={{ opacity: 0 }}
          animate={isInView ? { opacity: 1 } : {}}
          transition={{ duration: 0.6, delay: 0.9 }}
        >
          {t('market.bottomStats')}
        </motion.div>
      </div>
    </section>
  );
}
